from functools import lru_cache

@lru_cache(None)
def fib(n: int) -> int:
    if n == 0:
        return 0
    if n == 1:
        return 1
    return fib(n - 1) + fib(n - 2)

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1  # Increment to ensure the search space shrinks
        else:
            right = mid - 1  # Decrement to ensure the search space shrinks
    return -1

