def get_nested_value(data, keys):
    try:
        result = data
        for key in keys:
            result = result[key]
        return result
    except (KeyError, TypeError, IndexError, AttributeError):
        # KeyError: Key doesn't exist in dict
        # TypeError: Trying to index something that isn't indexable (e.g., an int)
        # IndexError: List index out of range
        # AttributeError: Object doesn't have __getitem__
        return None

